values
('additional-maths:6-3-the-binomial-distribution:match:190699e6', 'additional-maths', 'additional-maths:6-3-the-binomial-distribution', '6.3 The Binomial Distribution', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( 1 - (5/6)^4 \\)”?", "options": ["P(at least one 3) with 4 dice", "The probability of failure on one trial", "\\( X \\) is binomial: \\( n \\) trials, success probability \\( p \\)", "The binomial probability formula (provided on the sheet)"]}'::jsonb, '{"answer": 0, "explain": "“\\( 1 - (5/6)^4 \\)” means: P(at least one 3) with 4 dice"}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:mcq:825dcc52', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'mcq', 'mcq', 1, '{"question": "A spinner lands on red with probability \\( \\frac{2}{5} \\). It is spun twice. What is \\( P(\\text{red then red}) \\)?", "options": ["\\( \\frac{4}{25} \\)", "\\( \\frac{4}{5} \\)", "\\( \\frac{2}{5} \\)", "\\( \\frac{4}{10} \\)"]}'::jsonb, '{"answer": 0, "explain": "Multiply along the path: \\( \\frac{2}{5}\\times\\frac{2}{5} = \\frac{4}{25} \\). Adding the branches (\\( \\frac{4}{5} \\)) is the classic error."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:mcq:b270430a', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'mcq', 'mcq', 1, '{"question": "On a tree diagram, moving ALONG the branches (one event and then the next) you:", "options": ["Multiply the probabilities", "Add the probabilities", "Subtract them", "Divide them"]}'::jsonb, '{"answer": 0, "explain": "Along a path means ''AND'', so you multiply; adding is for separate paths (''OR'')."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:mcq:0f8cf10e', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'mcq', 'mcq', 1, '{"question": "To combine several separate paths that each give the wanted outcome (one path or another), you:", "options": ["Add the path probabilities", "Multiply the path probabilities", "Take the largest", "Subtract each from 1"]}'::jsonb, '{"answer": 0, "explain": "Different paths that all succeed are an ''OR'', so their probabilities add."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:mcq:189c4a22', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'mcq', 'mcq', 1, '{"question": "A bag has 4 red and 6 blue counters. Two are taken WITHOUT replacement. \\( P(\\text{red then red}) \\) is:", "options": ["\\( \\frac{4}{10}\\times\\frac{3}{9} = \\frac{2}{15} \\)", "\\( \\frac{4}{10}\\times\\frac{4}{10} = \\frac{4}{25} \\)", "\\( \\frac{4}{10}\\times\\frac{3}{10} \\)", "\\( \\frac{4}{9}\\times\\frac{3}{9} \\)"]}'::jsonb, '{"answer": 0, "explain": "After one red is kept, 3 red of 9 counters remain: \\( \\frac{4}{10}\\times\\frac{3}{9} = \\frac{2}{15} \\). Keeping \\( \\frac{4}{10} \\) twice ignores non-replacement."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:mcq:a8719d9e', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'mcq', 'mcq', 1, '{"question": "In a class of 30, 18 study art and 15 study music; 8 study both. How many study art only?", "options": ["\\( 10 \\)", "\\( 18 \\)", "\\( 8 \\)", "\\( 26 \\)"]}'::jsonb, '{"answer": 0, "explain": "Art only \\( = 18 - 8 = 10 \\); subtract the intersection from the art total."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:mcq:415e0cd0', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'mcq', 'mcq', 1, '{"question": "40 people are surveyed: 22 like tea, 15 like coffee and 5 like both. How many like at least one drink?", "options": ["\\( 32 \\)", "\\( 37 \\)", "\\( 42 \\)", "\\( 27 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( |T \\cup C| = 22 + 15 - 5 = 32 \\). Adding \\( 22+15 = 37 \\) double-counts the 5 in the overlap."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:mcq:458ee836', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'mcq', 'mcq', 1, '{"question": "A question asks how many students are in each Venn region. In the regions you should write:", "options": ["The counts (numbers of students)", "The probabilities as fractions", "Percentages", "Ratios"]}'::jsonb, '{"answer": 0, "explain": "Put counts in the regions unless the question specifically asks for probabilities."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:mcq:579f6a60', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'mcq', 'mcq', 1, '{"question": "On a Venn diagram, the members who are in NEITHER set are shown:", "options": ["Outside both circles but inside the rectangle", "In a third separate circle", "In the overlap of the two circles", "Outside the rectangle"]}'::jsonb, '{"answer": 0, "explain": "The ''neither'' group lives in the universal-set rectangle but outside every circle."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:mcq:be67f2b3', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'mcq', 'mcq', 1, '{"question": "A two-way table records 60 boys and 40 girls; 30 students wear glasses in total, of whom 18 are boys. How many girls wear glasses?", "options": ["\\( 12 \\)", "\\( 22 \\)", "\\( 42 \\)", "\\( 30 \\)"]}'::jsonb, '{"answer": 0, "explain": "Glasses column total is 30, so girls with glasses \\( = 30 - 18 = 12 \\)."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:mcq:d279aada', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'mcq', 'mcq', 1, '{"question": "In a survey of 100 people, 12 are girls who wear glasses. \\( P(\\text{a random person is a girl who wears glasses}) \\) is:", "options": ["\\( \\frac{12}{100} = \\frac{3}{25} \\)", "\\( \\frac{12}{40} \\)", "\\( \\frac{12}{30} \\)", "\\( \\frac{1}{12} \\)"]}'::jsonb, '{"answer": 0, "explain": "The probability is that region''s count over the grand total: \\( \\frac{12}{100} = \\frac{3}{25} \\)."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:mcq:2bfb5424', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'mcq', 'mcq', 1, '{"question": "When filling a three-set Venn diagram from data, you should start with:", "options": ["The number in all three sets (the centre)", "The grand total", "The ''none'' region", "Any single set"]}'::jsonb, '{"answer": 0, "explain": "Begin at the centre and work outward, subtracting so no one is counted twice."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:mcq:2c13cf2e', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'mcq', 'mcq', 1, '{"question": "The notation \\( A \\cap B \\) means the members who are:", "options": ["In both A and B", "In A or B or both", "In A but not B", "In neither A nor B"]}'::jsonb, '{"answer": 0, "explain": "\\( \\cap \\) is the intersection — in both sets. \\( \\cup \\) (union) is ''or both''."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:tf:2c844c2d', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'tf', 'tf', 1, '{"question": "Along the branches of a tree diagram you multiply the probabilities."}'::jsonb, '{"answer": true, "explain": "A whole path means one event AND the next, so the branch probabilities multiply."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:tf:d5a02b72', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'tf', 'tf', 1, '{"question": "To find the probability of one outcome OR another you multiply the path probabilities."}'::jsonb, '{"answer": false, "explain": "Separate paths (''OR'') are added; multiplying is for a single path (''AND'')."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:tf:a6961f14', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'tf', 'tf', 1, '{"question": "The ''neither'' group of a Venn diagram should be drawn as a third circle."}'::jsonb, '{"answer": false, "explain": "It is written outside the circles but inside the rectangle — never as an extra circle (a common examiner complaint)."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:tf:b7d41c36', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'tf', 'tf', 1, '{"question": "Every Venn diagram should be enclosed in a rectangle representing the universal set."}'::jsonb, '{"answer": true, "explain": "The rectangle is the universal set \\( \\xi \\); the answer box on the paper does not count as the rectangle."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:tf:3b7b523c', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'tf', 'tf', 1, '{"question": "When items are drawn without replacement, the probabilities on the second set of branches change."}'::jsonb, '{"answer": true, "explain": "The collection is smaller for the second draw, so those branch probabilities differ from the first."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:tf:3fbfcbda', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'tf', 'tf', 1, '{"question": "For two sets, \\( |A \\cup B| = |A| + |B| - |A \\cap B| \\)."}'::jsonb, '{"answer": true, "explain": "Adding the two totals counts the overlap twice, so subtract the intersection once."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:tf:a1f4f8a5', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'tf', 'tf', 1, '{"question": "When a question asks how many people are in each region, you should put probabilities in the regions."}'::jsonb, '{"answer": false, "explain": "Put counts in the regions unless probabilities are specifically requested."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:tf:069da9cb', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'tf', 'tf', 1, '{"question": "\\( P(\\text{at least one}) = 1 - P(\\text{none}) \\)."}'::jsonb, '{"answer": true, "explain": "''At least one'' is the complement of ''none'', so subtract \\( P(\\text{none}) \\) from 1."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:learn:d8e9e8fd', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'learn', 'mcq', 1, '{"readingTitle": "How do you use a tree diagram: multiply along, add across?", "reading": "<p>A <strong>tree diagram</strong> shows a sequence of events. Each branch is labelled with the probability of that outcome, and the branches from any single point always add up to \\( 1 \\).</p>\n            <ul>\n              <li><strong>Multiply ALONG the branches</strong> to find the probability of one outcome <em>AND</em> the next (a whole path from left to right).</li>\n              <li><strong>Add ACROSS the paths</strong> when several different paths all give the outcome you want (one path <em>OR</em> another).</li>\n              <li>Every complete path''s probabilities multiply to that path''s probability; all the path probabilities together add to \\( 1 \\).</li>\n            </ul>\n            <p><strong>Worked example.</strong> A bag holds 3 red and 2 blue counters. One is taken, its colour noted, and <em>replaced</em>; then a second is taken. So \\( P(R) = \\frac{3}{5} \\) and \\( P(B) = \\frac{2}{5} \\) on both draws.</p>\n            <svg viewBox=\"0 0 350 210\" width=\"100%\" style=\"max-width:380px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"Two-stage tree diagram for two draws with replacement from a bag of 3 red and 2 blue counters\">\n              <line x1=\"20\" y1=\"105\" x2=\"130\" y2=\"55\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <line x1=\"20\" y1=\"105\" x2=\"130\" y2=\"155\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <line x1=\"150\" y1=\"55\" x2=\"270\" y2=\"30\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <line x1=\"150\" y1=\"55\" x2=\"270\" y2=\"80\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <line x1=\"150\" y1=\"155\" x2=\"270\" y2=\"130\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <line x1=\"150\" y1=\"155\" x2=\"270\" y2=\"180\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <text x=\"58\" y=\"70\" fill=\"currentColor\" font-size=\"13\">3/5</text>\n              <text x=\"58\" y=\"140\" fill=\"currentColor\" font-size=\"13\">2/5</text>\n              <text x=\"136\" y=\"60\" fill=\"currentColor\" font-size=\"14\" font-weight=\"600\">R</text>\n              <text x=\"136\" y=\"160\" fill=\"currentColor\" font-size=\"14\" font-weight=\"600\">B</text>\n              <text x=\"203\" y=\"35\" fill=\"currentColor\" font-size=\"12\">3/5</text>\n              <text x=\"203\" y=\"78\" fill=\"currentColor\" font-size=\"12\">2/5</text>\n              <text x=\"203\" y=\"128\" fill=\"currentColor\" font-size=\"12\">3/5</text>\n              <text x=\"203\" y=\"182\" fill=\"currentColor\" font-size=\"12\">2/5</text>\n              <text x=\"278\" y=\"34\" fill=\"currentColor\" font-size=\"12\">RR = 9/25</text>\n              <text x=\"278\" y=\"84\" fill=\"currentColor\" font-size=\"12\">RB = 6/25</text>\n              <text x=\"278\" y=\"134\" fill=\"currentColor\" font-size=\"12\">BR = 6/25</text>\n              <text x=\"278\" y=\"184\" fill=\"currentColor\" font-size=\"12\">BB = 4/25</text>\n            </svg>\n            <p>\\( P(\\text{one of each colour}) = \\frac{3}{5}\\times\\frac{2}{5} + \\frac{2}{5}\\times\\frac{3}{5} = \\frac{6}{25} + \\frac{6}{25} = \\frac{12}{25} \\) — two paths (RB and BR) added.</p>", "question": "On a tree diagram, to find the probability of one event AND the next you:", "options": ["Multiply along the branches", "Add along the branches", "Add across the paths", "Subtract from 1"]}'::jsonb, '{"answer": 0, "explain": "Along a path (this AND that) you multiply; across separate paths (this OR that) you add."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:learn:0d0eaa5f', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'learn', 'mcq', 1, '{"readingTitle": "How does a tree diagram change without replacement?", "reading": "<p>If an item is <strong>not replaced</strong>, the second draw happens from a smaller collection, so the probabilities on the <strong>second set of branches change</strong> (both the numerator and the denominator can fall).</p>\n            <p><strong>Worked example.</strong> The same bag (3 red, 2 blue) but now the first counter is <em>kept</em>. The first draw is \\( P(R)=\\frac{3}{5} \\); if a red was taken, only 2 red of 4 remain, so the second draw is \\( P(R)=\\frac{2}{4} \\).</p>\n            <table class=\"worked\">\n              <tr><td>1. \\( P(\\text{both red}) = \\frac{3}{5}\\times\\frac{2}{4} = \\frac{6}{20} = \\frac{3}{10} \\).</td></tr>\n              <tr><td>2. \\( P(\\text{both blue}) = \\frac{2}{5}\\times\\frac{1}{4} = \\frac{2}{20} = \\frac{1}{10} \\).</td></tr>\n              <tr><td>3. \\( P(\\text{one of each}) = \\frac{3}{5}\\times\\frac{2}{4} + \\frac{2}{5}\\times\\frac{3}{4} = \\frac{6}{20}+\\frac{6}{20} = \\frac{3}{5} \\).</td></tr>\n            </table>\n            <p>Check: \\( \\frac{3}{10}+\\frac{1}{10}+\\frac{3}{5} = \\frac{3+1+6}{10} = 1 \\). ✓ The three whole-outcome probabilities must still add to \\( 1 \\).</p>\n            <p><strong>\"At least one\" trick:</strong> it is usually quicker to use \\( P(\\text{at least one}) = 1 - P(\\text{none}) \\) than to add several paths.</p>", "question": "Two counters are taken WITHOUT replacement from 3 red and 2 blue. \\( P(\\text{both red}) \\) is:", "options": ["\\( \\frac{3}{5}\\times\\frac{2}{4} = \\frac{3}{10} \\)", "\\( \\frac{3}{5}\\times\\frac{3}{5} = \\frac{9}{25} \\)", "\\( \\frac{3}{5}+\\frac{2}{4} \\)", "\\( \\frac{3}{5}\\times\\frac{3}{4} \\)"]}'::jsonb, '{"answer": 0, "explain": "After a red is kept, 2 red of 4 counters remain, so the second branch is \\( \\frac{2}{4} \\), giving \\( \\frac{3}{10} \\)."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:learn:3e6a8c24', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'learn', 'mcq', 1, '{"readingTitle": "How do you complete and read a two-way table?", "reading": "<p>A <strong>two-way table</strong> cross-classifies data by two features. Every <strong>row and every column adds up to its total</strong>, and the grand total sits in the corner — that is all you need to fill any missing cell.</p>\n            <p><strong>Worked example.</strong> 100 students are classified by gender and whether they wear glasses. Complete the table, then read off probabilities.</p>\n            <table class=\"worked\">\n              <tr><td></td><td><strong>Glasses</strong></td><td><strong>No glasses</strong></td><td><strong>Total</strong></td></tr>\n              <tr><td><strong>Boys</strong></td><td>18</td><td>42</td><td>60</td></tr>\n              <tr><td><strong>Girls</strong></td><td>12</td><td>28</td><td>40</td></tr>\n              <tr><td><strong>Total</strong></td><td>30</td><td>70</td><td>100</td></tr>\n            </table>\n            <ul>\n              <li>Boys, no glasses \\( = 60 - 18 = 42 \\); Girls total \\( = 100 - 60 = 40 \\); Girls glasses \\( = 30 - 18 = 12 \\).</li>\n              <li>\\( P(\\text{wears glasses}) = \\frac{30}{100} = \\frac{3}{10} \\).</li>\n              <li>\\( P(\\text{a girl who wears glasses}) = \\frac{12}{100} = \\frac{3}{25} \\).</li>\n            </ul>", "question": "In the table above, what is \\( P(\\text{a randomly chosen student is a boy who wears no glasses}) \\)?", "options": ["\\( \\frac{42}{100} = \\frac{21}{50} \\)", "\\( \\frac{18}{100} \\)", "\\( \\frac{42}{60} \\)", "\\( \\frac{70}{100} \\)"]}'::jsonb, '{"answer": 0, "explain": "42 boys wear no glasses out of 100 students, so \\( \\frac{42}{100} = \\frac{21}{50} \\)."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:learn:236bc222', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'learn', 'mcq', 1, '{"readingTitle": "How do you use a two-set Venn diagram?", "reading": "<p>A <strong>Venn diagram</strong> shows two overlapping circles inside a <strong>rectangle</strong> that stands for the <strong>universal set</strong> \\( \\xi \\) — everything being considered. Key notation:</p>\n            <ul>\n              <li>\\( A \\cap B \\) — the <strong>intersection</strong>: members in <em>both</em> A and B (the overlap).</li>\n              <li>\\( A \\cup B \\) — the <strong>union</strong>: members in A <em>or</em> B <em>or</em> both.</li>\n              <li>\\( A'' \\) — the <strong>complement</strong>: members <em>not</em> in A.</li>\n              <li>Members in <strong>neither</strong> set go <em>outside</em> both circles but <em>inside</em> the rectangle.</li>\n            </ul>\n            <p><strong>Put counts in the regions and work outward from the intersection.</strong> Example: 40 students, 25 study French, 18 study Spanish, 7 study both.</p>\n            <svg viewBox=\"0 0 300 210\" width=\"100%\" style=\"max-width:340px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"Two-set Venn diagram: French and Spanish, with 18 in French only, 7 in both, 11 in Spanish only and 4 in neither, inside a universal set of 40\">\n              <rect x=\"6\" y=\"6\" width=\"288\" height=\"198\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <circle cx=\"118\" cy=\"105\" r=\"72\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n              <circle cx=\"182\" cy=\"105\" r=\"72\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n              <text x=\"66\" y=\"30\" fill=\"currentColor\" font-size=\"13\" font-weight=\"600\">French</text>\n              <text x=\"196\" y=\"30\" fill=\"currentColor\" font-size=\"13\" font-weight=\"600\">Spanish</text>\n              <text x=\"80\" y=\"112\" fill=\"currentColor\" font-size=\"16\" text-anchor=\"middle\">18</text>\n              <text x=\"150\" y=\"112\" fill=\"currentColor\" font-size=\"16\" text-anchor=\"middle\">7</text>\n              <text x=\"220\" y=\"112\" fill=\"currentColor\" font-size=\"16\" text-anchor=\"middle\">11</text>\n              <text x=\"272\" y=\"194\" fill=\"currentColor\" font-size=\"14\" text-anchor=\"middle\">4</text>\n              <text x=\"20\" y=\"24\" fill=\"currentColor\" font-size=\"12\">ξ = 40</text>\n            </svg>\n            <p>Fill the <strong>overlap first</strong> (\\( 7 \\)), then French only \\( = 25-7 = 18 \\), Spanish only \\( = 18-7 = 11 \\). Neither \\( = 40 - (18+7+11) = 4 \\). Note \\( |A \\cup B| = |A| + |B| - |A \\cap B| = 25 + 18 - 7 = 36 \\), so \\( 40-36 = 4 \\) again.</p>", "question": "In a group of 30, 18 play tennis, 15 play squash and 8 play both. How many play tennis only?", "options": ["\\( 10 \\)", "\\( 18 \\)", "\\( 8 \\)", "\\( 26 \\)"]}'::jsonb, '{"answer": 0, "explain": "Tennis only \\( = 18 - 8 = 10 \\); subtract the overlap from the tennis total."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:learn:88155eb4', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'learn', 'mcq', 1, '{"readingTitle": "How do you fill a three-set Venn diagram?", "reading": "<p>With three circles there are <strong>seven regions</strong> inside plus the \"none\" region outside. Always <strong>start at the very centre</strong> (in all three sets) and <strong>work outward</strong>, subtracting as you go so nothing is double-counted.</p>\n            <p><strong>Worked example.</strong> 40 people are asked which of tea, coffee and juice they drink: 3 drink all three; 8 drink tea and coffee; 6 drink coffee and juice; 5 drink tea and juice; 20 drink tea; 18 drink coffee; 14 drink juice.</p>\n            <svg viewBox=\"0 0 320 300\" width=\"100%\" style=\"max-width:360px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"Three-set Venn diagram for tea, coffee and juice showing all seven region counts and 4 people in none\">\n              <rect x=\"6\" y=\"6\" width=\"308\" height=\"288\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <circle cx=\"120\" cy=\"120\" r=\"82\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n              <circle cx=\"200\" cy=\"120\" r=\"82\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n              <circle cx=\"160\" cy=\"188\" r=\"82\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n              <text x=\"66\" y=\"30\" fill=\"currentColor\" font-size=\"13\" font-weight=\"600\">Tea</text>\n              <text x=\"226\" y=\"30\" fill=\"currentColor\" font-size=\"13\" font-weight=\"600\">Coffee</text>\n              <text x=\"150\" y=\"290\" fill=\"currentColor\" font-size=\"13\" font-weight=\"600\">Juice</text>\n              <text x=\"88\" y=\"102\" fill=\"currentColor\" font-size=\"15\" text-anchor=\"middle\">10</text>\n              <text x=\"232\" y=\"102\" fill=\"currentColor\" font-size=\"15\" text-anchor=\"middle\">7</text>\n              <text x=\"160\" y=\"242\" fill=\"currentColor\" font-size=\"15\" text-anchor=\"middle\">6</text>\n              <text x=\"160\" y=\"92\" fill=\"currentColor\" font-size=\"15\" text-anchor=\"middle\">5</text>\n              <text x=\"118\" y=\"178\" fill=\"currentColor\" font-size=\"15\" text-anchor=\"middle\">2</text>\n              <text x=\"202\" y=\"178\" fill=\"currentColor\" font-size=\"15\" text-anchor=\"middle\">3</text>\n              <text x=\"160\" y=\"148\" fill=\"currentColor\" font-size=\"15\" text-anchor=\"middle\">3</text>\n              <text x=\"296\" y=\"286\" fill=\"currentColor\" font-size=\"14\" text-anchor=\"middle\">4</text>\n              <text x=\"20\" y=\"24\" fill=\"currentColor\" font-size=\"12\">ξ = 40</text>\n            </svg>\n            <table class=\"worked\">\n              <tr><td>1. Centre (all three) \\( = 3 \\).</td></tr>\n              <tr><td>2. Tea &amp; coffee only \\( = 8-3 = 5 \\); coffee &amp; juice only \\( = 6-3 = 3 \\); tea &amp; juice only \\( = 5-3 = 2 \\).</td></tr>\n              <tr><td>3. Tea only \\( = 20-(5+2+3) = 10 \\); coffee only \\( = 18-(5+3+3) = 7 \\); juice only \\( = 14-(2+3+3) = 6 \\).</td></tr>\n              <tr><td>4. None \\( = 40 - (10+7+6+5+3+2+3) = 40 - 36 = 4 \\).</td></tr>\n            </table>", "question": "When filling a three-set Venn diagram from totals, which region should you complete first?", "options": ["The centre — the number in all three sets", "The ''none'' region", "The grand total", "Any single-set region"]}'::jsonb, '{"answer": 0, "explain": "Start at the centre (all three) and work outward, subtracting so each region is counted once."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:learn:82c35997', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'learn', 'mcq', 1, '{"readingTitle": "What Venn conventions do examiners insist on?", "reading": "<p>These are the marks examiners report candidates lose most often on diagram questions — none of them are about the maths, all are about the <strong>conventions</strong>.</p>\n            <ul>\n              <li><strong>Always draw the universal-set rectangle.</strong> The answer box on the paper is <em>not</em> the rectangle — draw your own around the circles.</li>\n              <li><strong>The \"neither\" group is written outside the circles, inside the rectangle.</strong> Never draw it as a third, separate circle.</li>\n              <li><strong>Put COUNTS (numbers of items) in the regions</strong> unless the question asks for probabilities. Writing fractions where counts are wanted loses marks.</li>\n              <li><strong>Label the circles</strong> and, on a tree, label every branch with both the outcome and its probability.</li>\n              <li>\"<strong>Determine</strong>\" means show your working/justification — a bare number is not enough.</li>\n            </ul>\n            <p>Example: for \"10 like neither\", write \\( 10 \\) in the bottom corner of the rectangle, outside both rings — not in a new circle of its own.</p>", "question": "Where should the people who belong to NEITHER set be shown on a Venn diagram?", "options": ["Outside both circles but inside the rectangle", "In a separate third circle", "In the overlap of the two circles", "Outside the rectangle entirely"]}'::jsonb, '{"answer": 0, "explain": "The ''neither'' count goes in the universal-set rectangle but outside every circle — never as an extra circle."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:misc:a9a5dcc6', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Drawing the ''neither'' students in a third, separate circle inside the rectangle</p><p><strong>✅ The correct idea:</strong> The ''neither'' group is NOT a set of its own — write its count outside both circles but inside the universal-set rectangle. A weak answer invents a third ring; a strong answer puts, e.g., \\( 10 \\) in the corner of the rectangle.</p>", "question": "Where do the 10 students who like neither go?", "options": ["Outside both circles, inside the rectangle", "In a new third circle", "In the overlap", "Outside the rectangle"]}'::jsonb, '{"answer": 0, "explain": "''Neither'' is written in the rectangle but outside every circle."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:misc:135a83c0', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Drawing the circles with no rectangle around them</p><p><strong>✅ The correct idea:</strong> Without the rectangle there is no universal set shown, which loses a mark. A strong answer always draws the rectangle first and labels it \\( \\xi \\) with the grand total.</p>", "question": "What does the rectangle around the circles represent?", "options": ["The universal set (everything considered)", "The intersection", "The ''neither'' group only", "Nothing — it is decoration"]}'::jsonb, '{"answer": 0, "explain": "The rectangle is the universal set \\( \\xi \\)."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:misc:60a5125d', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Multiplying across the wrong branches, e.g. adding 0.5 + 0.6 for two events happening</p><p><strong>✅ The correct idea:</strong> For one event AND another you multiply along the path (\\( 0.5\\times0.6 = 0.3 \\)); you only add when combining separate complete paths. A weak answer adds along a path; a strong answer multiplies along and adds across.</p>", "question": "Two independent events have probabilities 0.5 and 0.6. \\( P(\\text{both}) \\) is:", "options": ["\\( 0.5\\times0.6 = 0.3 \\)", "\\( 0.5+0.6 = 1.1 \\)", "\\( 0.6-0.5 = 0.1 \\)", "\\( 0.5 \\)"]}'::jsonb, '{"answer": 0, "explain": "''Both'' is an AND, so multiply along the path: \\( 0.3 \\)."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:misc:d7adc7b5', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Finding the overlap by adding the two set totals, e.g. ''both = 50 + 20''</p><p><strong>✅ The correct idea:</strong> Use inclusion–exclusion: \\( |A\\cap B| = |A| + |B| - |A\\cup B| \\). Adding the totals double-counts the overlap. A strong answer sets the region total equal to those who like at least one and solves for the overlap.</p>", "question": "68 students; 10 like neither; 50 like pop, 20 like classical. How many like both?", "options": ["\\( 12 \\)", "\\( 70 \\)", "\\( 30 \\)", "\\( 58 \\)"]}'::jsonb, '{"answer": 0, "explain": "At least one \\( = 68-10 = 58 \\); \\( 50+20-\\text{both} = 58 \\Rightarrow \\text{both} = 12 \\)."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:misc:15743b39', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Keeping the first-draw probabilities on the second branches when there is no replacement</p><p><strong>✅ The correct idea:</strong> Without replacement the denominator (and sometimes numerator) falls for the second draw. A weak answer reuses \\( \\frac{3}{5} \\) twice; a strong answer uses \\( \\frac{3}{5}\\times\\frac{2}{4} \\).</p>", "question": "3 red, 2 blue, taken without replacement. The second branch after a red is:", "options": ["\\( \\frac{2}{4} \\) for another red", "\\( \\frac{3}{5} \\) for another red", "\\( \\frac{3}{4} \\) for another red", "\\( \\frac{2}{5} \\) for another red"]}'::jsonb, '{"answer": 0, "explain": "One red is gone: 2 red of 4 counters remain, so \\( \\frac{2}{4} \\)."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:tips:df77baaa', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'tips', 'mcq', 1, '{"readingTitle": "tip — Multiply along, add across", "reading": "<p><strong>Along a path = AND = multiply.</strong> <strong>Across paths = OR = add.</strong> For \"exactly one\" of three events, there are three winning paths (success in one place, failure in the other two) — work out each product, then add the three. For \"at least one\", use \\( 1 - P(\\text{none}) \\) instead of adding many paths.</p>", "question": "For ''exactly one of three events'', you should:", "options": ["Add the three single-success path probabilities", "Multiply all three success probabilities", "Use only one path", "Subtract from 3"]}'::jsonb, '{"answer": 0, "explain": "Each ''exactly one'' path is a product; add the three such paths together."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:tips:621724b3', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'tips', 'mcq', 1, '{"readingTitle": "explain — Counts, not probabilities, in Venn regions", "reading": "<p><strong>0 marks:</strong> filling the regions with fractions when the question wants numbers of people. <strong>Full marks:</strong> put the <em>count</em> in each region, draw the universal-set rectangle, and write the ''neither'' count outside the circles (never as a third circle). Only switch to probabilities if the question explicitly asks for them.</p>", "question": "A Venn question asks ''how many''. The regions should contain:", "options": ["Counts", "Probabilities", "Percentages", "Nothing"]}'::jsonb, '{"answer": 0, "explain": "''How many'' wants counts; use probabilities only when asked."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:tips:77c7276e', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'tips', 'mcq', 1, '{"readingTitle": "explain — ''Determine'' means show justification", "reading": "<p>The command word <strong>Determine</strong> requires visible working or reasoning, not just an answer. On \"Determine the number who liked both\", writing \\( 50 + 20 - \\text{both} = 58 \\Rightarrow \\text{both} = 12 \\) earns the method mark even before the final number — a bare \"12\" risks losing it.</p>", "question": "''Determine'' tells you to:", "options": ["Show working / justification for the answer", "Just write the answer down", "Give a decimal only", "Draw a graph"]}'::jsonb, '{"answer": 0, "explain": "''Determine'' demands justification, so show the method."}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:fib:3295c805', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'fib', 'fib', 2, '{"question": "Moving along the branches of a tree diagram you ___B1___ the probabilities; to combine several separate paths you ___B2___ them.", "blankOptions": {"B1": ["same", "counts", "total", "multiply"], "B2": ["inside", "rectangle", "circle", "add"]}}'::jsonb, '{"blanks": {"B1": "multiply", "B2": "add"}}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:fib:1d5e6ebf', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'fib', 'fib', 2, '{"question": "The people who are in neither set are written ___B1___ the circles but inside the ___B2___.", "blankOptions": {"B1": ["outside", "centre", "add", "same"], "B2": ["circle", "rectangle", "multiply", "probabilities"]}}'::jsonb, '{"blanks": {"B1": "outside", "B2": "rectangle"}}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:fib:4acd0d89', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'fib', 'fib', 2, '{"question": "The symbol \\( \\cap \\) stands for the ___B1___ (in both), and the symbol \\( \\cup \\) stands for the ___B2___ (in either).", "blankOptions": {"B1": ["outside", "subtract", "intersection", "inside"], "B2": ["circle", "union", "total", "counts"]}}'::jsonb, '{"blanks": {"B1": "intersection", "B2": "union"}}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:fib:37e6390c', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'fib', 'fib', 2, '{"question": "When filling a three-set Venn diagram, start from the ___B1___ where all three sets overlap and work ___B2___.", "blankOptions": {"B1": ["subtract", "change", "centre", "inside"], "B2": ["probabilities", "circle", "outward", "change"]}}'::jsonb, '{"blanks": {"B1": "centre", "B2": "outward"}}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:fib:a25aced4', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'fib', 'fib', 2, '{"question": "With replacement the probabilities on the second set of branches are the ___B1___ as the first; without replacement they ___B2___.", "blankOptions": {"B1": ["same", "counts", "outside", "rectangle"], "B2": ["change", "intersection", "union", "total"]}}'::jsonb, '{"blanks": {"B1": "same", "B2": "change"}}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:fib:82f5b549', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'fib', 'fib', 1, '{"question": "In a two-way table, each row and each column must add up to its ___B1___.", "blankOptions": {"B1": ["circle", "probabilities", "total", "multiply"]}}'::jsonb, '{"blanks": {"B1": "total"}}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:fib:b1b1bf01', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'fib', 'fib', 1, '{"question": "When a Venn question asks ''how many'', put ___B1___ (not probabilities) in each region.", "blankOptions": {"B1": ["subtract", "counts", "total", "multiply"]}}'::jsonb, '{"blanks": {"B1": "counts"}}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:match:69ffb8d7', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( A \\cap B \\)”?", "options": ["\\( 1 - P(\\text{none}) \\)", "In both A and B (intersection)", "Everything under consideration — the rectangle", "Second-draw probabilities change"]}'::jsonb, '{"answer": 1, "explain": "“\\( A \\cap B \\)” means: In both A and B (intersection)"}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:match:92a68a4c', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( A \\cup B \\)”?", "options": ["\\( 1 - P(\\text{none}) \\)", "Everything under consideration — the rectangle", "In A or B or both (union)", "Probability of one outcome OR another"]}'::jsonb, '{"answer": 2, "explain": "“\\( A \\cup B \\)” means: In A or B or both (union)"}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:match:c7781218', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( A'' \\)”?", "options": ["What to write for a ''how many'' question", "In both A and B (intersection)", "Method for filling a three-set Venn", "Not in A (complement)"]}'::jsonb, '{"answer": 3, "explain": "“\\( A'' \\)” means: Not in A (complement)"}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:match:4cef49f9', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( (A \\cup B)'' \\)”?", "options": ["Probability of one event AND the next", "In neither A nor B", "In A or B or both (union)", "Everything under consideration — the rectangle"]}'::jsonb, '{"answer": 1, "explain": "“\\( (A \\cup B)'' \\)” means: In neither A nor B"}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:match:a0f5e523', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Universal set \\( \\xi \\)”?", "options": ["Every row and column sums to its total", "Everything under consideration — the rectangle", "\\( 1 - P(\\text{none}) \\)", "Second-draw probabilities change"]}'::jsonb, '{"answer": 1, "explain": "“Universal set \\( \\xi \\)” means: Everything under consideration — the rectangle"}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:match:325f097e', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Multiply along the branches”?", "options": ["Probability of one outcome OR another", "Probability of one event AND the next", "What to write for a ''how many'' question", "In neither A nor B"]}'::jsonb, '{"answer": 1, "explain": "“Multiply along the branches” means: Probability of one event AND the next"}'::jsonb),
('additional-maths:6-4-tree-two-way-and-venn-diagrams:match:25500934', 'additional-maths', 'additional-maths:6-4-tree-two-way-and-venn-diagrams', '6.4 Tree, Two-Way and Venn Diagrams', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Add across the paths”?", "options": ["Method for filling a three-set Venn", "Probability of one outcome OR another", "What to write for a ''how many'' question", "Everything under consideration — the rectangle"]}'::jsonb, '{"answer": 1, "explain": "“Add across the paths” means: Probability of one outcome OR another"}'::jsonb),
